
import {IonImg} from '@ionic/vue'
import {computed, toRefs} from "vue";

export default {
    name: 'TasteBuddyLogo',
    props: {
        size: {
            type: String,
            default: '200px',
            required: false
        },
        withLeftMargin: {
            type: Boolean,
            required: false
        }
    },
    components: {
        IonImg
    },
    setup(props: { size?: string }) {
        const {size} = toRefs(props)

        const pixelSize = computed(() => {
            switch (size?.value ?? 'medium') {
                case 'tiny':
                    return '50px'
                case 'small':
                    return '100px'
                case 'medium':
                    return '200px'
                case 'large':
                    return '300px'
                default:
                    return size?.value ?? '200px'
            }
        })

        return {
            pixelSize,
        }
    }
}
