
import {computed, ref, watch} from 'vue';
import {IonButton, IonCard, IonCardContent, IonCardHeader, IonInput, IonItem, useIonRouter} from '@ionic/vue';
import TasteBuddyLogo from '@/components/TasteBuddyLogo.vue'
import {useUserStore} from '@/storage';
import {useRoute} from 'vue-router';

export default {
    name: 'SignIn',
    components: {
        IonButton,
        IonCard,
        IonCardContent,
        IonCardHeader,
        IonInput,
        IonItem,
        TasteBuddyLogo,
    },
    setup() {
        const username = ref('');
        const password = ref('');
        const isDisabled = computed(() => username.value.length === 0 || password.value.length === 0)

        const route = useRoute()
        const router = useIonRouter()
        const redirect = computed(() => (route.query.redirect ?? '') as string)

        const store = useUserStore();
        const isAuthenticated = computed(() => store.isAuthenticated)
        /* Redirect if already logged in */
        watch(isAuthenticated, () => {
            if (isAuthenticated.value) {
                router.push(redirect.value)
            }
        })

        /* Login */
        const authenticate = () => {
            store.basicAuth({
                username: username.value,
                password: password.value,
            }).then((success: boolean) => {
                if (success) {
                    router.push(redirect.value)
                }
            })
        }


        return {
            username, password,
            isDisabled,
            authenticate,
        };
    },
};
